   359→// Create interview (POST to /interviews)
   360→router.post('/interviews', authMiddleware, requireRecruiter, async (req, res) => {
   361→  try {
   362→    const {
   363→      application_id, scheduled_at, duration = 60,
   364→      interview_type = 'video', notes
   365→    } = req.body;
