   452→
   453→// Update application status
   454→router.put('/applications/:id', authMiddleware, requireRecruiter, async (req, res) => {
   455→  try {
   456→    const { status, recruiter_notes } = req.body;
   457→
   458→    // Verify application belongs to company
   459→    const existing = await pool.query(
   460→      'SELECT id, job_id, candidate_id FROM job_applications WHERE id = $1 AND company_id = $2',
   461→      [req.params.id, req.user.company_id]
   462→    );
   463→
   464→    if (existing.rows.length === 0) {
   465→      return res.status(404).json({ error: 'Application not found' });
   466→    }
   467→
   468→    const result = await pool.query(
   469→      `UPDATE job_applications SET
   470→        status = COALESCE($1, status),
   471→        recruiter_notes = COALESCE($2, recruiter_notes),
   472→        updated_at = NOW()
   473→       WHERE id = $3
   474→       RETURNING *`,
   475→      [status, recruiter_notes, req.params.id]
   476→    );
   477→
   478→    // Update job analytics
   479→    if (status) {
   480→      const app = existing.rows[0];
   481→
   482→      // Update counters based on status
   483→      if (status === 'interviewed') {
   484→        await pool.query(
   485→          'UPDATE job_analytics SET interviews_scheduled = interviews_scheduled + 1 WHERE job_id = $1',
   486→          [app.job_id]
   487→        );
   488→      } else if (status === 'offered') {
   489→        await pool.query(
   490→          'UPDATE job_analytics SET offers_made = offers_made + 1 WHERE job_id = $1',
   491→          [app.job_id]
   492→        );
   493→
   494→        // Update hiring ratio score
   495→        await trustscoreService.updateHiringRatioScore(req.user.company_id);
   496→      } else if (status === 'hired') {
   497→        await pool.query(
   498→          'UPDATE job_analytics SET offers_accepted = offers_accepted + 1 WHERE job_id = $1',
   499→          [app.job_id]
   500→        );
   501→      }
   502→    }
   503→
   504→    // Audit log: Application status change
   505→    if (status) {
   506→      await AuditLogger.log({
   507→        actionType: 'application_status_changed',
   508→        userId: req.user.id,
   509→        targetType: 'job_application',
   510→        targetId: parseInt(req.params.id),
   511→        metadata: {
   512→          candidate_id: existing.rows[0].candidate_id,
   513→          job_id: existing.rows[0].job_id,
   514→          new_status: status,
   515→          recruiter_notes: recruiter_notes || null
   516→        },
   517→        req
   518→      });
   519→    }
   520→
   521→    res.json({ success: true, application: result.rows[0] });
