   528→// Schedule interview
   529→router.post('/interviews/schedule', authMiddleware, requireRecruiter, async (req, res) => {
   530→  try {
   531→    const {
   532→      job_id, candidate_id, scheduled_at, duration_minutes = 60,
   533→      interview_type = 'video', meeting_link, notes
   534→    } = req.body;
   535→
   536→    if (!job_id || !candidate_id || !scheduled_at) {
   537→      return res.status(400).json({ error: 'Job, candidate, and scheduled time are required' });
   538→    }
   539→
   540→    // Verify job belongs to company
   541→    const job = await pool.query(
   542→      'SELECT id FROM jobs WHERE id = $1 AND company_id = $2',
   543→      [job_id, req.user.company_id]
   544→    );
   545→
   546→    if (job.rows.length === 0) {
   547→      return res.status(404).json({ error: 'Job not found' });
   548→    }
   549→
   550→    const result = await pool.query(
   551→      `INSERT INTO scheduled_interviews
   552→       (company_id, job_id, candidate_id, recruiter_id, scheduled_at, duration_minutes, interview_type, meeting_link, notes)
   553→       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
   554→       RETURNING *`,
   555→      [req.user.company_id, job_id, candidate_id, req.user.id,
   556→       scheduled_at, duration_minutes, interview_type, meeting_link, notes]
   557→    );
