   187→router.post('/resume/upload', authMiddleware, upload.single('resume'), async (req, res) => {
   188→  try {
   189→    if (!req.file) {
   190→      return res.status(400).json({ error: 'No file uploaded' });
   191→    }
   192→
   193→    // Upload to R2
   194→    const formData = new FormData();
   195→    formData.append('file', req.file.buffer, {
   196→      filename: req.file.originalname,
   197→      contentType: req.file.mimetype
   198→    });
   199→
   200→    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
   201→      method: 'POST',
   202→      headers: {
   203→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
   204→        ...formData.getHeaders()
   205→      },
   206→      body: formData
   207→    });
   208→
   209→    const uploadResult = await uploadRes.json();
   210→    if (!uploadResult.success) {
   211→      throw new Error(uploadResult.error?.message || 'Upload failed');
   212→    }
   213→
   214→    // Save parsed resume record
   215→    const resumeRecord = await pool.query(`
   216→      INSERT INTO parsed_resumes (user_id, original_filename, file_url, parsing_status)
   217→      VALUES ($1, $2, $3, 'processing')
   218→      RETURNING id
   219→    `, [req.user.id, req.file.originalname, uploadResult.file.url]);
   220→
   221→    // Update profile with resume URL
   222→    await pool.query(`
   223→      INSERT INTO candidate_profiles (user_id, resume_url)
   224→      VALUES ($1, $2)
   225→      ON CONFLICT (user_id) DO UPDATE SET resume_url = $2, updated_at = NOW()
   226→    `, [req.user.id, uploadResult.file.url]);
   227→
   228→    // Parse the resume text (convert buffer to text for now - in production would use OCR)
   229→    const resumeText = req.file.buffer.toString('utf-8');
   230→
   231→    // Get user's subscription for tracking
   232→    const user = await pool.query('SELECT stripe_subscription_id FROM users WHERE id = $1', [req.user.id]);
   233→    const subscriptionId = user.rows[0]?.stripe_subscription_id;
   234→
   235→    // Parse with AI
   236→    const parsedData = await parseResume(resumeText, { subscriptionId });
   237→
   238→    // Update the record with parsed data
   239→    await pool.query(`
   240→      UPDATE parsed_resumes
   241→      SET parsed_data = $1, parsing_status = 'completed', parsed_at = NOW()
   242→      WHERE id = $2
   243→    `, [JSON.stringify(parsedData), resumeRecord.rows[0].id]);
   244→
   245→    res.json({
   246→      success: true,
   247→      resume_url: uploadResult.file.url,
   248→      parsed_data: parsedData,
   249→      resume_id: resumeRecord.rows[0].id
   250→    });
   251→  } catch (err) {
   252→    console.error('Resume upload error:', err);
   253→    res.status(500).json({ error: 'Failed to upload and parse resume' });
   254→  }
   255→});
