    67→      `SELECT o.*,
    68→        j.title as job_title,
    69→        j.company
    70→      FROM offers o
    71→      LEFT JOIN jobs j ON o.job_id = j.id
    72→      WHERE o.candidate_id = $1
    73→      ORDER BY o.created_at DESC`,
    74→      [req.user.id]
    75→    );
    76→
    77→    res.json(result.rows);
    78→  } catch (err) {
    79→    console.error('Error fetching offers:', err);
