    81→  }
    82→});
    83→
    84→// Send offer to candidate
    85→router.post('/offers/:id/send', authMiddleware, async (req, res) => {
    86→  try {
    87→    const result = await pool.query(
    88→      `UPDATE offers
    89→       SET status = 'sent', sent_at = NOW(), updated_at = NOW()
    90→       WHERE id = $1 AND company_id = $2
    91→       RETURNING *`,
    92→      [req.params.id, req.user.company_id]
    93→    );
    94→
    95→    if (result.rows.length === 0) {
    96→      return res.status(404).json({ error: 'Offer not found' });
    97→    }
    98→
    99→    res.json(result.rows[0]);
